1	/** Coordinates of a cell on the infinite grid: [x, y]. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [0, -1], [1, -1],
6	  [-1,  0],          [1,  0],
7	  [-1,  1], [0,  1], [1,  1],
8	];
9	
10	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
11	
12	/**
13	 * Computes the next generation of live cells per Conway's Game of Life rules.
14	 * Returns the set of cells alive after one tick.
15	 */
16	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
17	  const liveKeys = new Set(liveCells.map(cellKey));
18	  const neighbors = new Map<string, { cell: Cell; count: number }>();
19	  for (const [x, y] of liveCells) {
20	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
21	      const cell: Cell = [x + dx, y + dy];
22	      const key = cellKey(cell);
23	      const entry = neighbors.get(key);
24	      if (entry) entry.count++;
25	      else neighbors.set(key, { cell, count: 1 });
26	    }
27	  }
28	  const survives = (key: string, count: number): boolean =>
29	    count === 3 || (count === 2 && liveKeys.has(key));
30	  return [...neighbors]
31	    .filter(([key, { count }]) => survives(key, count))
32	    .map(([, { cell }]) => cell);
33	};
