1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(result.sort()).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]].sort());
17	  });
18	  it("Rule 2 survival: middle of 3-in-a-row survives with exactly 2 live neighbors", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
20	    expect(result).toContainEqual([1, 0]);
21	  });
22	  it("Rule 3 overpopulation: live cell with more than 3 live neighbors dies", () => {
23	    // Gen 0: '###' top, '.#.' mid, '###' bot — center (1,1) has 6 live neighbors
24	    const gen0: [number, number][] = [
25	      [0, 0], [1, 0], [2, 0],
26	      [1, 1],
27	      [0, 2], [1, 2], [2, 2],
28	    ];
29	    const result = nextGeneration(gen0);
30	    expect(result).not.toContainEqual([1, 1]);
31	  });
32	  it("Rule 4 reproduction: L-shape — dead (1,1) with 3 neighbors becomes alive", () => {
33	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
34	    expect(result.map(c => c.join(",")).sort()).toEqual(
35	      [[0, 0], [1, 0], [0, 1], [1, 1]].map(c => c.join(",")).sort()
36	    );
37	  });
38	  it("blinker oscillator vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
39	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
40	    expect(result.map(c => c.join(",")).sort()).toEqual(
41	      [[-1, 1], [0, 1], [1, 1]].map(c => c.join(",")).sort()
42	    );
43	  });
44	  it("handles negative coordinates — blinker shifted into negative space", () => {
45	    const result = nextGeneration([[-5, -5], [-5, -4], [-5, -3]]);
46	    expect(result.map(c => c.join(",")).sort()).toEqual(
47	      [[-6, -4], [-5, -4], [-4, -4]].map(c => c.join(",")).sort()
48	    );
49	  });
50	});
